<?php
namespace App\Http\Controllers;
use App\Models\Business; use Illuminate\Http\RedirectResponse; use Illuminate\Http\Request; use Illuminate\View\View;
class BusinessController extends Controller { public function create(): View { return view('businesses.create'); } public function store(Request $request): RedirectResponse { $data=$request->validate(['name'=>'required|string|max:255','legal_name'=>'nullable|string|max:255','email'=>'nullable|email','phone'=>'nullable|string|max:50','currency'=>'required|string|size:3','vat_rate'=>'required|numeric|min:0|max:100','address'=>'nullable|string|max:500','city'=>'nullable|string|max:100','state'=>'nullable|string|max:100','country'=>'required|string|max:100','tax_id'=>'nullable|string|max:100']); $business=$request->user()->businesses()->create($data + ['owner_id'=>$request->user()->id], ['role'=>'owner']); $request->user()->forceFill(['current_business_id'=>$business->id])->save(); return redirect()->route('dashboard')->with('status','Business created.'); } public function edit(Business $business): View { $this->authorize('update',$business); return view('businesses.edit', compact('business')); } public function update(Request $request, Business $business): RedirectResponse { $this->authorize('update',$business); $business->update($request->validate(['name'=>'required|string|max:255','legal_name'=>'nullable|string|max:255','email'=>'nullable|email','phone'=>'nullable|string|max:50','currency'=>'required|string|size:3','vat_rate'=>'required|numeric|min:0|max:100','address'=>'nullable|string|max:500','city'=>'nullable|string|max:100','state'=>'nullable|string|max:100','country'=>'required|string|max:100','tax_id'=>'nullable|string|max:100'])); return back()->with('status','Business updated.'); } public function switch(Request $request, Business $business): RedirectResponse { abort_unless($request->user()->businesses()->whereKey($business->id)->exists(),403); $request->user()->forceFill(['current_business_id'=>$business->id])->save(); return redirect()->route('dashboard'); } }
